mapper.select:
SELECT
t.*,
t1.real_name create_user_name,
t2.name create_dept_name,
t3.name create_post_name
FROM
castle_config_sms t
LEFT OUTER JOIN castle_sys_user t1 ON t.create_user  = t1.id
LEFT OUTER JOIN castle_sys_dept t2 ON t.create_dept  = t2.id
LEFT OUTER JOIN castle_sys_post t3 ON t.create_post = t3.id
WHERE
t.is_deleted = 2

    AND t.id = #{configSmsEntity.id}


    AND t.sms_code = #{configSmsEntity.smsCode}


    AND t.platform = #{configSmsEntity.platform}


    AND t.sms_config = #{configSmsEntity.smsConfig}


    AND t.remark = #{configSmsEntity.remark}


    AND t.status = #{configSmsEntity.status}


    AND t.create_user = #{configSmsEntity.createUser}


    AND t.create_dept = #{configSmsEntity.createDept}


    AND t.create_post = #{configSmsEntity.createPost}


    AND t.create_time = #{configSmsEntity.createTime}


    AND t.update_user = #{configSmsEntity.updateUser}


    AND t.update_time = #{configSmsEntity.updateTime}


    AND t.is_deleted = #{configSmsEntity.isDeleted}

    order by create_time desc

    limit #{map.offset},#{map.rows}

SELECT
count(1)
FROM
castle_config_sms t
WHERE
t.is_deleted = 2

    AND t.id = #{configSmsEntity.id}


    AND t.sms_code = #{configSmsEntity.smsCode}


    AND t.platform = #{configSmsEntity.platform}


    AND t.sms_config = #{configSmsEntity.smsConfig}


    AND t.remark = #{configSmsEntity.remark}


    AND t.status = #{configSmsEntity.status}


    AND t.create_user = #{configSmsEntity.createUser}


    AND t.create_dept = #{configSmsEntity.createDept}


    AND t.create_post = #{configSmsEntity.createPost}


    AND t.create_time = #{configSmsEntity.createTime}


    AND t.update_user = #{configSmsEntity.updateUser}


    AND t.update_time = #{configSmsEntity.updateTime}


    AND t.is_deleted = #{configSmsEntity.isDeleted}
